svg.script:
const lines = [
  "🎓 B.Tech CSE Student at Barak Valley Engineering College",
  "💻 Full Stack Developer (React, Next.js, Flutter)",
  "🚀 Founder of 8bitbannar – Web Development Company",
  "🧠 Exploring AI/ML and modern web technologies",
  "🌍 Building projects that solve real-world problems",
  "⚡ Always learning and improving"
];

let lineIndex = 0;
let charIndex = 0;

function typeLine() {
  if (lineIndex >= lines.length) return;

  const currentLine = lines[lineIndex];
  const target = document.getElementById(`line${lineIndex + 1}`);

  if (charIndex < currentLine.length) {
    target.textContent += currentLine.charAt(charIndex);
    charIndex++;
    setTimeout(typeLine, 30);
  } else {
    lineIndex++;
    charIndex = 0;
    setTimeout(typeLine, 400);
  }
}

typeLine();
